using BookLoans.Abstractions.Models;using BookLoans.Abstractions.Interfaces;using BookLoans.Data.Entities;using Microsoft.EntityFrameworkCore;namespace BookLoans.Data.Repositories;public class AdminCheckoutRepository(AppDbContext dbContext) : IAdminCheckoutRepository{    public async Task<IReadOnlyList<BookLoan>> GetCheckoutsAsync(CancellationToken ct)    {        List<BookLoanEntity> loans = await dbContext.BookLoans            .AsNoTracking()            .Include(loan => loan.BookEntity)            .ThenInclude(book => book.Photos)            .Include(loan => loan.BookEntity)            .ThenInclude(book => book.BookAuthors)            .ThenInclude(ba => ba.AuthorEntity)            .Include(loan => loan.BorrowerEntity)            .OrderByDescending(loan => loan.CheckedOutAtUtc)            .ToListAsync(ct);        return loans            .Select(loan => loan.ToBookLoanDto())            .ToList();    }    public async Task<BookLoan> GetCreateFormAsync(int? preselectedBookId, int? preselectedBorrowerId, CancellationToken ct)    {        IReadOnlyList<Book> books = await GetBookOptionsAsync(ct);        IReadOnlyList<Borrower> borrowers = await GetBorrowerOptionsAsync(ct);        int bookId = preselectedBookId.HasValue && books.Any(book => book.Id == preselectedBookId.Value)            ? preselectedBookId.Value            : books.FirstOrDefault()?.Id ?? 0;        int borrowerId = preselectedBorrowerId.HasValue && borrowers.Any(borrower => borrower.Id == preselectedBorrowerId.Value)            ? preselectedBorrowerId.Value            : borrowers.FirstOrDefault()?.Id ?? 0;        return new BookLoan        {            BookId = bookId,            BorrowerId = borrowerId,            Books = books,            Borrowers = borrowers        };    }    public async Task<BookLoan> RebuildFormAsync(BookLoan model, CancellationToken ct)    {        IReadOnlyList<Book> books = await GetBookOptionsAsync(ct);        IReadOnlyList<Borrower> borrowers = await GetBorrowerOptionsAsync(ct);        return new BookLoan        {            BookId = model.BookId,            BorrowerId = model.BorrowerId,            Books = books,            Borrowers = borrowers        };    }    public async Task<string?> CreateAsync(BookLoan model, CancellationToken ct)    {        BookEntity? book = await dbContext.Books            .FirstOrDefaultAsync(entity => entity.Id == model.BookId, ct);        if (book is null)        {            return "Please select a valid book.";        }        BorrowerEntity? borrower = await dbContext.Borrowers            .FirstOrDefaultAsync(entity => entity.Id == model.BorrowerId, ct);        if (borrower is null)        {            return "Please select a valid borrower.";        }        bool hasActiveCheckout = await dbContext.BookLoans            .AnyAsync(loan => loan.BookId == model.BookId && loan.ReturnedAtUtc == null, ct);        if (hasActiveCheckout)        {            return "This book is already checked out.";        }        BookLoanEntity loan = BookLoanEntity.FromFormDto(model);        book.CurrentBorrowerId = model.BorrowerId;        dbContext.BookLoans.Add(loan);        await dbContext.SaveChangesAsync(ct);        return null;    }    public async Task<string?> ReturnAsync(int loanId, CancellationToken ct)    {        BookLoanEntity? loan = await dbContext.BookLoans            .Include(entity => entity.BookEntity)            .FirstOrDefaultAsync(entity => entity.Id == loanId, ct);        if (loan is null)        {            return "Checkout not found.";        }        if (loan.ReturnedAtUtc is not null)        {            return "This checkout has already been returned.";        }        loan.ReturnedAtUtc = DateTime.UtcNow;        loan.BookEntity.CurrentBorrowerId = null;        await dbContext.SaveChangesAsync(ct);        return null;    }    private async Task<IReadOnlyList<Book>> GetBookOptionsAsync(CancellationToken ct)    {        List<BookEntity> books = await dbContext.Books            .AsNoTracking()            .Include(book => book.BookAuthors)            .ThenInclude(bookAuthor => bookAuthor.AuthorEntity)            .Include(book => book.Loans)            .OrderBy(book => book.Title)            .ToListAsync(ct);        return books            .Select(book => book.ToAdminCheckoutBookOptionDto())            .ToList();    }    private async Task<IReadOnlyList<Borrower>> GetBorrowerOptionsAsync(CancellationToken ct)    {        List<BorrowerEntity> borrowers = await dbContext.Borrowers            .AsNoTracking()            .OrderBy(borrower => borrower.LastName)            .ThenBy(borrower => borrower.FirstName)            .ToListAsync(ct);        return borrowers            .Select(borrower => borrower.ToAdminCheckoutBorrowerOptionDto())            .ToList();    }}